    strncat(cmd_buffer, ip_addr, buffer_size - 1 - strlen(cmd_buffer));
    strncat(cmd_buffer, netmask_separator, buffer_size - 1 - strlen(cmd_buffer));
    strncat(cmd_buffer, netmask, buffer_size - 1 - strlen(cmd_buffer));
    strncat(cmd_buffer, gateway_separator, buffer_size - 1 - strlen(cmd_buffer));
    strncat(cmd_buffer, gateway, buffer_size - 1 - strlen(cmd_buffer));

    // Success
    return 0;
}
